import{_ as a,o as s,c as n,ae as t}from"./chunks/framework.Dn7Y7LSn.js";const h=JSON.parse('{"title":"ADR-001: Teammate System Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"reference/ADR-001-TEAMMATE-SYSTEM.md","filePath":"reference/ADR-001-TEAMMATE-SYSTEM.md"}'),i={name:"reference/ADR-001-TEAMMATE-SYSTEM.md"};function l(r,e,o,c,p,d){return s(),n("div",null,[...e[0]||(e[0]=[t(`<h1 id="adr-001-teammate-system-architecture" tabindex="-1">ADR-001: Teammate System Architecture <a class="header-anchor" href="#adr-001-teammate-system-architecture" aria-label="Permalink to &quot;ADR-001: Teammate System Architecture&quot;">​</a></h1><p><strong>Date</strong>: 2026-02-23<br><strong>Status</strong>: Proposed<br><strong>Author</strong>: heliosHarness Team</p><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>We need to implement a teammate/subagent system in heliosHarness, inspired by Claude Code&#39;s teammates feature and adapted for Codex CLI. This system must support:</p><ul><li>Multiple specialized teammates (coder, reviewer, tester, researcher)</li><li>Async delegation with status tracking</li><li>Safe multi-agent coordination</li><li>Resource-aware execution</li></ul><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>We will implement a <strong>Registry + Delegation Protocol + Executor</strong> architecture:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                    TeammateManager                       │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  ┌─────────────┐  ┌─────────────┐  ┌────────────────┐  │</span></span>
<span class="line"><span>│  │   Teammate  │  │ Delegation  │  │  Codex CLI     │  │</span></span>
<span class="line"><span>│  │  Registry   │──│  Protocol   │──│   Executor     │  │</span></span>
<span class="line"><span>│  └─────────────┘  └─────────────┘  └────────────────┘  │</span></span>
<span class="line"><span>│         │                │                  │            │</span></span>
<span class="line"><span>│         ▼                ▼                  ▼            │</span></span>
<span class="line"><span>│  ┌─────────────────────────────────────────────────┐    │</span></span>
<span class="line"><span>│  │              Coordination Layer                  │    │</span></span>
<span class="line"><span>│  │  (Circuit Breaker, Bulkhead, Queue)            │    │</span></span>
<span class="line"><span>│  └─────────────────────────────────────────────────┘    │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────┘</span></span></code></pre></div><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><h3 id="positive" tabindex="-1">Positive <a class="header-anchor" href="#positive" aria-label="Permalink to &quot;Positive&quot;">​</a></h3><ul><li>Clear separation of concerns</li><li>Extensible for future executor types (not just Codex)</li><li>Testable components in isolation</li><li>Follows proven patterns from thegent</li></ul><h3 id="negative" tabindex="-1">Negative <a class="header-anchor" href="#negative" aria-label="Permalink to &quot;Negative&quot;">​</a></h3><ul><li>Additional complexity vs. simple implementation</li><li>Requires careful coordination to avoid conflicts</li></ul><h3 id="neutral" tabindex="-1">Neutral <a class="header-anchor" href="#neutral" aria-label="Permalink to &quot;Neutral&quot;">​</a></h3><ul><li>May need to adjust based on Codex CLI API evolution</li></ul><h2 id="alternatives-considered" tabindex="-1">Alternatives Considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives Considered&quot;">​</a></h2><ol><li><strong>Direct Codex CLI invocation</strong> - Simpler but less flexible</li><li><strong>MCP-based subagents</strong> - More complex setup, better isolation</li><li><strong>Full thegent integration</strong> - Would require tight coupling</li></ol><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li>TEAMMATES_RESEARCH_AND_PLAN.md (thegent)</li><li>Codex CLI subagent research (web)</li></ul>`,19)])])}const m=a(i,[["render",l]]);export{h as __pageData,m as default};
